import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.Cd7uensT.js";const m=JSON.parse('{"title":"系统设置页面重写设计","description":"","frontmatter":{},"headers":[],"relativePath":"dev/specs/system-settings-rewrite.md","filePath":"dev/specs/system-settings-rewrite.md","lastUpdated":1781600659000}'),s={name:"dev/specs/system-settings-rewrite.md"};function o(i,t,n,l,h,b){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="系统设置页面重写设计" tabindex="-1">系统设置页面重写设计 <a class="header-anchor" href="#系统设置页面重写设计" aria-label="Permalink to &quot;系统设置页面重写设计&quot;">​</a></h1><blockquote><p>原文：<a href="https://github.com/gituib/idc_assest/blob/master/docs/superpowers/specs/2026-06-12-system-settings-rewrite-design.md" target="_blank" rel="noreferrer">docs/superpowers/specs/2026-06-12-system-settings-rewrite-design.md</a></p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>重写系统设置主页面（<code>SystemSettings.jsx</code>），遵循务实原则：每个设置项都必须有实际效果。移除所有&quot;只写不读&quot;的设置项，新增 maintenance_mode 和 max_login_attempts 的后端执行逻辑。</p><p><strong>范围</strong>：仅重写系统设置主页面，备份相关 3 个页面保持不变。</p><h2 id="设计决策" tabindex="-1">设计决策 <a class="header-anchor" href="#设计决策" aria-label="Permalink to &quot;设计决策&quot;">​</a></h2><ul><li><strong>方案 A</strong>：保持 3 Tab 结构（基本设置、外观设置、关于系统）</li><li><strong>务实派</strong>：移除所有无实际效果的设置项，保留的每个设置项都必须有前后端闭环</li><li><strong>精简优先</strong>：不新增功能，先做精简</li></ul><h2 id="设置项清单" tabindex="-1">设置项清单 <a class="header-anchor" href="#设置项清单" aria-label="Permalink to &quot;设置项清单&quot;">​</a></h2><h3 id="tab-1-基本设置" tabindex="-1">Tab 1：基本设置 <a class="header-anchor" href="#tab-1-基本设置" aria-label="Permalink to &quot;Tab 1：基本设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>设置项</th><th>Key</th><th>类型</th><th>实际效果</th></tr></thead><tbody><tr><td>站点名称</td><td>site_name</td><td>string</td><td>浏览器 title</td></tr><tr><td>空闲超时</td><td>idle_timeout</td><td>number</td><td>前端 idle-timeout hook</td></tr><tr><td>最大登录尝试</td><td>max_login_attempts</td><td>number</td><td>后端登录限流</td></tr><tr><td>维护模式</td><td>maintenance_mode</td><td>boolean</td><td>后端中间件拦截</td></tr></tbody></table><h3 id="tab-2-外观设置" tabindex="-1">Tab 2：外观设置 <a class="header-anchor" href="#tab-2-外观设置" aria-label="Permalink to &quot;Tab 2：外观设置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>设置项</th><th>Key</th><th>类型</th><th>实际效果</th></tr></thead><tbody><tr><td>登录页背景</td><td>login_bg</td><td>upload</td><td>登录页背景图</td></tr><tr><td>站点 Logo</td><td>site_logo</td><td>upload</td><td>左上角 Logo</td></tr></tbody></table><p>更多详情请查看完整设计文档。</p>',13)])])}const p=e(s,[["render",o]]);export{m as __pageData,p as default};
